#!/usr/bin/env python3
from __future__ import annotations

import re
from pathlib import Path

from feature_presets import build_tab_specs


HUD_METHOD = """
- (void)setUpHUD {
    [SVProgressHUD setBackgroundColor:RGBA(0, 0, 0, 0.5)];
    [SVProgressHUD setFont:[UIFont fontWithName:@"PingFang SC" size:14]];
    [SVProgressHUD setForegroundColor:[UIColor whiteColor]];
    [SVProgressHUD setMinimumSize:CGSizeMake(200, 120)];
    [SVProgressHUD setCornerRadius:15];
    [SVProgressHUD setMaximumDismissTimeInterval:0.8];
}
""".strip("\n")


def _build_add_child_method(tab_specs: list[dict]) -> str:
    lines = ["- (void)addChildViewControllers {"]
    for tab in tab_specs:
        lines.append(
            "    [self addChildViewControllerWithController:[[{class_name} alloc] init] "
            "andNavigationBarTitle:NSLocalizedString(@\"{nav_title}\", nil) "
            "andTabBarTitle:NSLocalizedString(@\"{tab_title}\", nil) "
            "andTabBarImageName:@\"{image_name}\"];".format(
                class_name=tab["class_name"],
                nav_title=tab["nav_title"],
                tab_title=tab["tab_title"],
                image_name=tab["image_name"],
            )
        )
    lines.append("}")
    return "\n".join(lines)


def _ensure_imports(content: str, headers: list[str]) -> tuple[str, list[str]]:
    existing_headers = {
        match.group(1)
        for match in re.finditer(r'^#import\s+"([^"]+)"\s*$', content, flags=re.M)
    }
    missing_headers = [header for header in headers if header not in existing_headers]
    if not missing_headers:
        return content, []

    import_matches = list(re.finditer(r'^#import\s+"[^"]+"\s*$', content, flags=re.M))
    if not import_matches:
        raise RuntimeError("MainViewController.m 里没找到 import 区域，无法自动补 import")

    insert_at = import_matches[-1].end()
    import_block = "".join(f'\n#import "{header}"' for header in missing_headers)
    return content[:insert_at] + import_block + content[insert_at:], missing_headers


def _ensure_hud_call(content: str) -> tuple[str, bool]:
    if "[self setUpHUD];" in content:
        return content, False

    anchor = "[self addChildViewControllers];"
    if anchor not in content:
        raise RuntimeError("MainViewController.m 里没找到 addChildViewControllers 调用，无法补 setUpHUD")

    updated = content.replace(anchor, anchor + "\n    [self setUpHUD];", 1)
    return updated, True


def _ensure_hud_method(content: str) -> tuple[str, bool]:
    if "- (void)setUpHUD" in content:
        return content, False

    anchor = "\n\n#pragma mark - 加入统一的导航控制器"
    if anchor not in content:
        raise RuntimeError("MainViewController.m 里没找到导航控制器标记，无法插入 setUpHUD")

    updated = content.replace(anchor, "\n\n" + HUD_METHOD + anchor, 1)
    return updated, True


def _replace_add_child_method(content: str, tab_specs: list[dict]) -> tuple[str, bool]:
    pattern = re.compile(r"- \(void\)addChildViewControllers \{\n.*?\n\}", re.S)
    replacement = _build_add_child_method(tab_specs)
    updated, count = pattern.subn(replacement, content, count=1)
    if count != 1:
        raise RuntimeError("MainViewController.m 里没找到 addChildViewControllers 方法，无法自动替换")
    return updated, updated != content


def patch_main_view_controller(project_dir: Path, project_name: str, feature_names: list[str]) -> dict:
    main_view_controller_path = project_dir / project_name / "Controller" / "MainViewController.m"
    if not main_view_controller_path.is_file():
        return {
            "patched": False,
            "main_view_controller_path": str(main_view_controller_path),
            "tab_count": 0,
            "tabs": [],
            "missing_tab_presets": [],
            "imports_added": [],
            "hud_call_added": False,
            "hud_method_added": False,
        }

    tab_specs, missing_tab_presets = build_tab_specs(feature_names)
    if not tab_specs:
        return {
            "patched": False,
            "main_view_controller_path": str(main_view_controller_path),
            "tab_count": 0,
            "tabs": [],
            "missing_tab_presets": missing_tab_presets,
            "imports_added": [],
            "hud_call_added": False,
            "hud_method_added": False,
        }

    content = main_view_controller_path.read_text(encoding="utf-8")
    content, imports_added = _ensure_imports(content, [tab["import_header"] for tab in tab_specs])
    content, hud_call_added = _ensure_hud_call(content)
    content, hud_method_added = _ensure_hud_method(content)
    content, tabs_replaced = _replace_add_child_method(content, tab_specs)

    if imports_added or hud_call_added or hud_method_added or tabs_replaced:
        main_view_controller_path.write_text(content, encoding="utf-8")

    return {
        "patched": bool(imports_added or hud_call_added or hud_method_added or tabs_replaced),
        "main_view_controller_path": str(main_view_controller_path),
        "tab_count": len(tab_specs),
        "tabs": tab_specs,
        "missing_tab_presets": missing_tab_presets,
        "imports_added": imports_added,
        "hud_call_added": hud_call_added,
        "hud_method_added": hud_method_added,
    }

#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
from pathlib import Path

from common import (
    DEFAULT_DEST_ROOT,
    DEFAULT_FEATURE_SOURCE_ROOT,
    DEFAULT_TEMPLATE_BUILTIN_FEATURES,
    SOURCE_EXTENSIONS,
    iter_project_files,
    normalize_feature_names,
    normalize_keywords,
    split_feature_names,
    split_keywords,
)
from feature_presets import is_template_builtin_feature, resolve_feature_name


GROUP_ROOTS = {"Controller", "View", "Model", "Manager", "Tool", "Shared", "Resource", "NotSure"}


def detect_module_path(relative_parts: list[str]) -> str:
    if len(relative_parts) < 3:
        return "/".join(relative_parts)

    if len(relative_parts) < 4:
        return "/".join(relative_parts[:2])

    category = relative_parts[2]
    if category not in GROUP_ROOTS:
        return "/".join(relative_parts[:3])

    if len(relative_parts) >= 5 and category != "Tool":
        return "/".join(relative_parts[:4])
    return "/".join(relative_parts[:3])


def score_file(path_text: str, content: str, keywords: list[str]) -> tuple[int, list[str]]:
    score = 0
    matched: list[str] = []
    lowered_path = path_text.lower()
    lowered_content = content.lower()

    for keyword in keywords:
        hit = False
        if keyword in lowered_path:
            score += 6
            hit = True
        count = lowered_content.count(keyword)
        if count:
            score += min(count, 4)
            hit = True
        if hit and keyword not in matched:
            matched.append(keyword)
    return score, matched


def find_feature_matches(feature_root: Path, feature_names: list[str], limit: int) -> dict:
    feature_names = normalize_feature_names(feature_names)
    builtin_features = set(DEFAULT_TEMPLATE_BUILTIN_FEATURES)
    template_builtin_features = [
        name for name in feature_names if name in builtin_features or is_template_builtin_feature(name)
    ]
    feature_names_for_scan = [name for name in feature_names if name not in template_builtin_features]
    if not feature_names:
        return {
            "feature_source_root": str(feature_root.resolve()),
            "feature_names": [],
            "template_builtin_features": [],
            "matched_feature_count": 0,
            "matches": [],
            "missing_features": [],
        }
    if not feature_names_for_scan:
        return {
            "feature_source_root": str(feature_root.resolve()),
            "feature_names": feature_names,
            "template_builtin_features": template_builtin_features,
            "matched_feature_count": 0,
            "matches": [],
            "missing_features": [],
        }

    feature_map: dict[str, str] = {}
    for name in feature_names_for_scan:
        feature_map[name.casefold()] = name
        resolved_name = resolve_feature_name(name)
        if resolved_name:
            feature_map[resolved_name.casefold()] = name
    grouped: dict[tuple[str, str], dict] = {}
    matched_features: set[str] = set()

    for path in iter_project_files(feature_root):
        if path.suffix.lower() not in SOURCE_EXTENSIONS and path.name != "Podfile":
            continue

        try:
            relative_parts = list(path.relative_to(feature_root).parts)
        except ValueError:
            continue

        matched_index = -1
        matched_name = ""
        for index, part in enumerate(relative_parts):
            feature_name = feature_map.get(part.strip().casefold())
            if feature_name:
                matched_index = index
                matched_name = feature_name
                break

        if matched_index < 0:
            continue

        module_path = "/".join(relative_parts[: matched_index + 1])
        key = (matched_name, module_path)
        item = grouped.setdefault(
            key,
            {
                "feature_name": matched_name,
                "project": relative_parts[0] if relative_parts else "",
                "module_path": module_path,
                "file_count": 0,
                "files": [],
            },
        )
        item["file_count"] += 1
        item["files"].append(str(path.relative_to(feature_root)))
        matched_features.add(matched_name)

    matches = []
    for item in grouped.values():
        matches.append(
            {
                "feature_name": item["feature_name"],
                "project": item["project"],
                "module_path": item["module_path"],
                "file_count": item["file_count"],
                "files": sorted(item["files"])[:12],
            }
        )
    matches.sort(key=lambda item: (item["feature_name"], item["module_path"]))

    return {
