        if child.get("path") == name or child.get("name") == name:
            return child_id
    return None


def _ensure_group(objects: dict, app_group_id: str, group_parts: list[str]) -> str:
    current_group_id = app_group_id
    for part in group_parts:
        existing_group_id = _find_child_group(objects, current_group_id, part)
        if existing_group_id:
            current_group_id = existing_group_id
            continue

        group_id = _generate_id(objects)
        objects[group_id] = {
            "isa": "PBXGroup",
            "children": [],
            "path": part,
            "sourceTree": "<group>",
        }
        objects[current_group_id].setdefault("children", []).append(group_id)
        current_group_id = group_id
    return current_group_id


def _file_reference_payload(filename: str) -> dict:
    suffix = Path(filename).suffix.lower()
    if suffix in FOLDER_TYPE_MAP:
        return {
            "isa": "PBXFileReference",
            "lastKnownFileType": FOLDER_TYPE_MAP[suffix],
            "path": filename,
            "sourceTree": "<group>",
        }
    return {
        "isa": "PBXFileReference",
