def _ensure_build_file(objects: dict, build_phase_files: list[str], file_ref_id: str) -> str:
    for build_file_id in build_phase_files:
        build_file = objects.get(build_file_id)
        if build_file and build_file.get("fileRef") == file_ref_id:
