    }
    build_phase_files.append(build_file_id)
    return build_file_id


def _replace_tokens(value: str, rename_map: dict[str, str]) -> str:
    updated = value
    for old, new in rename_map.items():
        updated = updated.replace(old, new)
    return updated


def _collect_source_files(source_root: Path) -> list[Path]:
    if source_root.is_dir():
        return [
            path
            for path in sorted(source_root.rglob("*"))
            if path.is_file() and not should_ignore_file(path)
        ]
    if source_root.is_file() and not should_ignore_file(source_root):
        return [source_root]

    parent = source_root.parent
    if not parent.is_dir():
        return []

    return [
        path
        for path in sorted(parent.glob(source_root.name + ".*"))
        if path.is_file() and not should_ignore_file(path)
    ]


def _copy_source(source_root: Path, dest_dir: Path, rename_map: dict[str, str]) -> list[Path]:
    copied_files: list[Path] = []
    source_files = _collect_source_files(source_root)
    for source_path in source_files:
        if source_root.is_dir():
            relative_path = source_path.relative_to(source_root)
        else:
            relative_path = Path(source_path.name)

        renamed_parts = [_replace_tokens(part, rename_map) for part in relative_path.parts]
        target_path = dest_dir.joinpath(*renamed_parts)
        target_path.parent.mkdir(parents=True, exist_ok=True)

        if is_text_file(source_path):
            content = source_path.read_text(encoding="utf-8", errors="ignore")
            target_path.write_text(_replace_tokens(content, rename_map), encoding="utf-8")
        else:
            shutil.copy2(source_path, target_path)

        copied_files.append(target_path)
    return copied_files


def _register_file(
    objects: dict,
    app_group_id: str,
    source_phase_files: list[str],
    resource_phase_files: list[str],
    app_root: Path,
    dest_file: Path,
) -> None:
    relative_to_app = dest_file.relative_to(app_root)
    parent_group_parts = list(relative_to_app.parts[:-1])
    parent_group_id = _ensure_group(objects, app_group_id, parent_group_parts)
    filename = relative_to_app.name

    file_ref_id = _find_child_file_ref(objects, parent_group_id, filename)
    if not file_ref_id:
        file_ref_id = _generate_id(objects)
        objects[file_ref_id] = _file_reference_payload(filename)
        objects[parent_group_id].setdefault("children", []).append(file_ref_id)

    suffix = dest_file.suffix.lower()
    if suffix in SOURCE_BUILD_EXTENSIONS:
        _ensure_build_file(objects, source_phase_files, file_ref_id)
    elif suffix in RESOURCE_BUILD_EXTENSIONS or suffix in FOLDER_TYPE_MAP:
        _ensure_build_file(objects, resource_phase_files, file_ref_id)


def _normalize_image_key(path: Path) -> str:
    return IMAGE_SCALE_SUFFIX_RE.sub("", path.stem)


def _build_resource_index(search_root: Path) -> tuple[dict[str, list[Path]], dict[str, list[Path]]]:
    exact_index: dict[str, list[Path]] = {}
    image_index: dict[str, list[Path]] = {}
    for path in iter_project_files(search_root):
        suffix = path.suffix.lower()
        if suffix not in RESOURCE_SEARCH_EXTENSIONS:
            continue
        exact_index.setdefault(path.name, []).append(path)
        if suffix in {".png", ".jpg", ".jpeg", ".pdf"}:
            image_index.setdefault(_normalize_image_key(path), []).append(path)
    return exact_index, image_index


def _extract_resource_names(source_files: list[Path]) -> set[str]:
    resource_names: set[str] = set()
    for path in source_files:
        if not is_text_file(path):
            continue
        content = path.read_text(encoding="utf-8", errors="ignore")
        for name in IMAGE_NAMED_RE.findall(content):
            if name and name.startswith("A_"):
                resource_names.add(name)
        for name, ext in URL_RESOURCE_RE.findall(content):
            if name and ext:
                resource_names.add(f"{name}.{ext}")
        for literal_name in RESOURCE_LITERAL_RE.findall(content):
            if literal_name:
                resource_names.add(literal_name)
    return resource_names


def _resource_matches(resource_name: str, exact_index: dict[str, list[Path]], image_index: dict[str, list[Path]]) -> list[Path]:
    if "." in resource_name:
        return sorted(exact_index.get(resource_name, []))
    return sorted(image_index.get(resource_name, []))


def _resource_dest_parts(feature_name: str, preset: dict | None, candidate: Path, resource_name: str) -> tuple[str, str]:
    tab = (preset or {}).get("tab") or {}
    image_name = str(tab.get("image_name") or "")
    if image_name and (resource_name == image_name or resource_name.startswith(image_name + "-")):
        return "Resource", "Main"

    resource_group = str((preset or {}).get("resource_group") or "")
    if resource_group:
        return "Resource", resource_group

    if "Resource" in candidate.parts:
        resource_index = candidate.parts.index("Resource")
        if len(candidate.parts) > resource_index + 1:
            return "Resource", get_feature_group_name(feature_name, candidate.parts[resource_index + 1])

    return "Resource", get_feature_group_name(feature_name, "Main")


def _apply_group_name(feature_name: str, relative_module_parts: list[str], preset: dict | None) -> list[str]:
    if len(relative_module_parts) < 2:
        return relative_module_parts
    group_name = get_feature_group_name(feature_name, relative_module_parts[1])
    if group_name:
        updated_parts = list(relative_module_parts)
        updated_parts[1] = group_name
        return updated_parts
    return relative_module_parts


def integrate_feature_modules(
    project_dir: Path,
    project_name: str,
    feature_source_root: Path,
    feature_matches: list[dict],
    search_root: Path,
    enable_resource_auto_copy: bool = False,
) -> dict:
    if not feature_matches:
        return {
            "integrated_module_count": 0,
            "integrated_modules": [],
            "copied_file_count": 0,
            "copied_resource_count": 0,
            "copied_resources": [],
            "missing_resources": [],
            "pbxproj_updated": False,
        }

    app_root = project_dir / project_name
    pbxproj_path = project_dir / f"{project_name}.xcodeproj" / "project.pbxproj"
    pbxproj = _load_pbxproj_json(pbxproj_path)
    objects = pbxproj["objects"]

    app_group_id = _find_object_id(objects, "PBXGroup", path=project_name)
    target_id = _find_object_id(objects, "PBXNativeTarget", name=project_name)
    target = objects[target_id]
    source_phase_id = next(
        phase_id for phase_id in target["buildPhases"] if objects[phase_id]["isa"] == "PBXSourcesBuildPhase"
    )
    resource_phase_id = next(
        phase_id for phase_id in target["buildPhases"] if objects[phase_id]["isa"] == "PBXResourcesBuildPhase"
    )
    source_phase_files = objects[source_phase_id].setdefault("files", [])
    resource_phase_files = objects[resource_phase_id].setdefault("files", [])

    integrated_modules: list[dict] = []
    integrated_source_files: list[Path] = []
    copied_file_count = 0
    seen_copy_keys: set[tuple[str, str]] = set()

    def append_copy_plan(feature_name: str, module_path: str, dest_parts: list[str], rename_map: dict[str, str], source_root: Path) -> None:
        copy_key = (feature_name, module_path)
        if copy_key in seen_copy_keys:
            return
        seen_copy_keys.add(copy_key)

        dest_dir = app_root.joinpath(*dest_parts)
        copied_files = _copy_source(source_root, dest_dir, rename_map)
        if not copied_files:
            return

        nonlocal copied_file_count
        copied_file_count += len(copied_files)
        integrated_source_files.extend(copied_files)

        for dest_file in copied_files:
            _register_file(objects, app_group_id, source_phase_files, resource_phase_files, app_root, dest_file)

        integrated_modules.append(
            {
                "feature_name": feature_name,
                "module_path": module_path,
                "dest_path": str(dest_dir),
                "copied_file_count": len(copied_files),
            }
        )

    for match in feature_matches:
        module_path = match["module_path"]
        module_parts = Path(module_path).parts
        if len(module_parts) < 2:
            continue

        preset = get_feature_preset(match["feature_name"])
        rename_map = dict((preset or {}).get("rename_map") or {})

        source_root = feature_source_root.joinpath(*module_parts)
        relative_module_parts = _apply_group_name(match["feature_name"], list(module_parts[1:]), preset)
        append_copy_plan(match["feature_name"], module_path, relative_module_parts, rename_map, source_root)

        extra_modules = (preset or {}).get("extra_modules") or ()
        for extra_module in extra_modules:
            extra_path = str(extra_module["module_path"])
            extra_source_root = feature_source_root.joinpath(*Path(extra_path).parts)
            append_copy_plan(
                match["feature_name"],
                extra_path,
                list(extra_module["dest_parts"]),
                rename_map,
                extra_source_root,
            )

    copied_resources: list[dict] = []
    missing_resources: list[str] = []
    if enable_resource_auto_copy:
        exact_index, image_index = _build_resource_index(search_root)
        copied_resource_keys: set[tuple[str, str]] = set()

        for match in feature_matches:
            preset = get_feature_preset(match["feature_name"])
            feature_module_files = [
                path
                for path in integrated_source_files
                if match["feature_name"] in {
                    item["feature_name"]
                    for item in integrated_modules
                    if str(path).startswith(item["dest_path"])
                }
            ]
            resource_names = sorted(_extract_resource_names(feature_module_files))

            for resource_name in resource_names:
                candidates = _resource_matches(resource_name, exact_index, image_index)
                if not candidates:
                    if resource_name not in missing_resources:
                        missing_resources.append(resource_name)
                    continue

                for candidate in candidates:
                    dest_root_name, dest_group_name = _resource_dest_parts(
                        match["feature_name"],
                        preset,
                        candidate,
                        resource_name,
                    )
                    dest_dir = app_root / dest_root_name / dest_group_name
                    dest_dir.mkdir(parents=True, exist_ok=True)
                    dest_path = dest_dir / candidate.name
                    copy_key = (resource_name, str(dest_path))
                    if copy_key in copied_resource_keys:
                        continue
                    copied_resource_keys.add(copy_key)

                    if not dest_path.exists():
                        shutil.copy2(candidate, dest_path)
                    _register_file(objects, app_group_id, source_phase_files, resource_phase_files, app_root, dest_path)
                    copied_resources.append(
                        {
                            "feature_name": match["feature_name"],
                            "resource_name": resource_name,
                            "source_path": str(candidate),
                            "dest_path": str(dest_path),
                        }
                    )

    _write_pbxproj_xml(pbxproj_path, pbxproj)
    subprocess.run(["plutil", "-lint", str(pbxproj_path)], check=True, capture_output=True, text=True)

    return {
        "integrated_module_count": len(integrated_modules),
        "integrated_modules": integrated_modules,
        "copied_file_count": copied_file_count,
        "copied_resource_count": len(copied_resources),
        "copied_resources": copied_resources,
        "missing_resources": sorted(missing_resources),
        "pbxproj_updated": bool(integrated_modules or copied_resources),
    }

