    [self.view addSubview:self.scrollView];
    [self.scrollView addSubview:self.contentView];

    // 顶部
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.right.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(86));
    }];

    // scroll
    [_scrollView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.bottom.equalTo(self.view);
        make.top.equalTo(self.headerView.mas_bottom);
    }];

    // content
    [_contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.scrollView);
        make.width.equalTo(self.scrollView);
    }];

    // 顶部开启按钮
    [self.contentView addSubview:self.topEnableView];
    [self.topEnableView addSubview:self.enableTitleLabel];
    [self.topEnableView addSubview:self.enableSwitch];

    [_topEnableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(20));
        make.left.right.equalTo(self.contentView).inset(ZOOM(16));
        make.height.mas_equalTo(ZOOM(54));
    }];

    [_enableTitleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.topEnableView).offset(ZOOM(20));
        make.centerY.equalTo(self.topEnableView);
    }];

    [_enableSwitch mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.topEnableView).offset(ZOOM(-20));
        make.centerY.equalTo(self.topEnableView);
    }];

    // 下方设置区域
    [self.contentView addSubview:self.reminderSettingView];

    [_reminderSettingView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.topEnableView.mas_bottom).offset(ZOOM(16));
        make.left.right.equalTo(self.contentView).inset(ZOOM(16));
        make.height.mas_equalTo(ZOOM(112));
    }];

    // 间隔
    [self.reminderSettingView addSubview:self.intervalButton];
    [self.reminderSettingView addSubview:self.intervalValueLabel];
    [self.reminderSettingView addSubview:self.interImage];

    [_intervalButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.left.right.equalTo(self.reminderSettingView);
        make.height.mas_equalTo(ZOOM(56));
    }];

    [_intervalValueLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.intervalButton).offset(ZOOM(-45));
        make.centerY.equalTo(self.intervalButton);
    }];

    [_interImage mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.intervalButton).offset(ZOOM(-16));
        make.centerY.equalTo(self.intervalButton);
        make.height.width.mas_equalTo(ZOOM(24));
    }];

    // 次数
    [self.reminderSettingView addSubview:self.frequencyButton];
    [self.reminderSettingView addSubview:self.frequencyValueLabel];
    [self.reminderSettingView addSubview:self.frequencyImage];

    [_frequencyButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.right.equalTo(self.reminderSettingView);
        make.top.equalTo(self.intervalButton.mas_bottom).offset(ZOOM(16));
        make.height.mas_equalTo(ZOOM(56));
    }];

    [_frequencyValueLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.frequencyButton).offset(ZOOM(-45));
        make.centerY.equalTo(self.frequencyButton);
    }];

    [_frequencyImage mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.frequencyButton).offset(ZOOM(-16));
        make.centerY.equalTo(self.frequencyButton);
        make.height.width.mas_equalTo(ZOOM(24));
    }];

    // content bottom 处理
    [self.contentView mas_makeConstraints:^(MASConstraintMaker *make) {
        self.contentBottomConstraint = make.bottom.equalTo(self.reminderSettingView.mas_bottom).offset(40);
    }];
}

#pragma mark - 交互

/// Switch 开关
- (void)enableSwitchChanged:(UISwitch *)sender {
    self.remindEnabled = sender.isOn;
    [self updateSettingState];
}

/// 根据开关改变可点击状态 + UI
- (void)updateSettingState {

    self.intervalButton.userInteractionEnabled = self.remindEnabled;
    self.frequencyButton.userInteractionEnabled = self.remindEnabled;

    CGFloat alpha = self.remindEnabled ? 1.0 : 0.4;
    self.reminderSettingView.alpha = alpha;
}

/// 点击“提醒间隔”
- (void)intervalButtonTapped {
    NSArray *items = @[@"5分钟", @"10分钟", @"15分钟", @"20分钟", @"25分钟", @"30分钟"];

    SelectorPopupView *popup = [[SelectorPopupView alloc] initWithItems:items];
    popup.selectCallback = ^(NSString *title, NSInteger index) {
        self.intervalValueLabel.text = title;
    };
    [popup showFromView:self.intervalButton inView:self.view];
}

/// 点击“提醒次数”
- (void)frequencyButtonTapped {
    NSArray *items = @[@"1次", @"2次", @"3次", @"4次", @"5次"];

    SelectorPopupView *popup = [[SelectorPopupView alloc] initWithItems:items];
    popup.selectCallback = ^(NSString *title, NSInteger index) {
        self.frequencyValueLabel.text = title;
    };
    [popup showFromView:self.frequencyButton inView:self.view];
}

