+        _titleLabel.textColor = UIColor.darkTextColor;
+    }
+    return _titleLabel;
+}
+
+- (UIImageView *)checkIcon {
+    if (!_checkIcon) {
+        _checkIcon = [[UIImageView alloc] init];
+        _checkIcon.image = [UIImage imageNamed:@"check"];
+        _checkIcon.hidden = YES;
+    }
+    return _checkIcon;
+}
+
