#import "CategoryCell.h"
#import <Masonry/Masonry.h>

@implementation CategoryCell

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        [self setupUI];
        self.backgroundColor = UIColor.clearColor;
    }
    return self;
}

- (void)setupUI {
    [self.contentView addSubview:self.containView];
    [self.contentView addSubview:self.titleLabel];
    [self.contentView addSubview:self.checkIcon];

    [self.containView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.contentView);
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.containView).offset(16);
        make.centerY.equalTo(self.containView);
    }];

    [self.checkIcon mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.containView).offset(-16);
        make.centerY.equalTo(self.containView);
        make.width.height.mas_equalTo(20);
    }];
}

#pragma mark - public

- (void)setChecked:(BOOL)checked {
    self.checkIcon.hidden = !checked;
    self.titleLabel.textColor = checked ? UIColor.blueColor : UIColor.darkTextColor;
}

#pragma mark - lazy

- (UIView *)containView {
    if (!_containView) {
        _containView = [[UIView alloc] init];
        _containView.backgroundColor = UIColor.whiteColor;
        _containView.layer.cornerRadius = 14;
    }
    return _containView;
}

- (UILabel *)titleLabel {
    if (!_titleLabel) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.font = [UIFont systemFontOfSize:16 weight:UIFontWeightMedium];
        _titleLabel.textColor = UIColor.darkTextColor;
    }
    return _titleLabel;
}

- (UIImageView *)checkIcon {
    if (!_checkIcon) {
        _checkIcon = [[UIImageView alloc] init];
        _checkIcon.image = [UIImage imageNamed:@"check"];
        _checkIcon.hidden = YES;
    }
    return _checkIcon;
}

@end

